mapper.select:
SELECT A.PROP_CD, A.CMPX_CD,
       A.CHECK_IN_TIME, A.CHECK_IN_TIME_TO, A.CHECK_OUT_CLOSE_TIME
  FROM PMS.PMS_COMPLEX_CONF_R A
 WHERE A.PROP_CD = #{propCd}
   AND A.CMPX_CD = #{cmpxCd}

SELECT A.USER_ID, A.USER_NM,
       A.USER_TP, A.DEPT_CD,
       A.USER_MOBILE, A.USER_WK_STAT
  FROM PMS.PMS_USER_MTR A
 WHERE A.PROP_CD = #{propCd}
   AND A.CMPX_CD = #{cmpxCd}

   AND A.DEPT_CD = #{deptCd}

   AND A.USE_YN  = 'Y'
 ORDER BY A.USER_NM
